var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REPLY_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나 이 로봇 알아. 그라운드 원에서 정기 안전 교육 할 때 본 적 있음.</color>","JPN":"<color=#ffd34c>このロボット見たことある。グラウンド・ワンで定期安全教育訓練の時見た。</color>","ENG":"<color=#ffd34c>I know this robot. I saw him at the Ground One regular safety training.</color>","TWN":"<color=#ffd34c>我知道這個機器人，在 G1 進行定期安全教育時見過。</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REPLY_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>무슨 작은 태스크포스 사장님이라고 그러던데?</color>","JPN":"<color=#ffd34c>どっかの小規模タスクフォースの社長って聞いたよ。</color>","ENG":"<color=#ffd34c>I heard he’s a CEO of a small TASKFORCE company.</color>","TWN":"<color=#ffd34c>聽說是一家小小特遣勢力公司的老闆？</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REPLY_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나 캄파멘토에서 일하는데 위에 진심?</color>","JPN":"<color=#ffd34c>俺、カンパメントで働いてるけど、↑マジか？</color>","ENG":"<color=#ffd34c>I work in Campamento, are you for real?</color>","TWN":"<color=#ffd34c>我在坎帕門托工作，樓上認真？</color>"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흐응……. 그럴 줄 알았어. 그라운드 원의 사장님이었잖아.","JPN":"へえ、やっぱりな。グラウンド・ワンの社長だったんだ。","ENG":"Hmm... I knew it. He’s the CEO from Ground One.","TWN":"嗯… 我就知道會這樣，原來是 G1 的老闆。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"이런…… 빌어먹을!","JPN":"……くそ！","ENG":"Darn it!","TWN":"糟糕… 該死的！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"왜 갑자기 성질이야, 아저씨? 또 데이팅 앱에서 차였어?","JPN":"急にどうしたの、おっさん。またマッチングアプリでブロックでもされたか？","ENG":"Why are you so upset, old man? Got dumped on a dating app again?","TWN":"大叔幹嘛突然發火？又在交友軟體上被甩啦？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"바보 같은 소리 작작하고 이거나 봐!","JPN":"馬鹿を言うんじゃねえ。これを見ろ！","ENG":"Shut up and look at this!","TWN":"少說廢話，你看這個！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그 멍청한 펭귄들이랑 꼬맹이들이 찍은 영상이야!","JPN":"あのペンギンどもとガキどもが撮った映像だ！","ENG":"It’s a video with those stupid penguins and kids!","TWN":"這是那些笨企鵝和小鬼們拍的影片！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"우리가 바이럴 업체에 의뢰해서 여론 조작했던 게 죄다 수포로 돌아갔다고!","JPN":"俺らがバイラル広告代理店に依頼して情報操作をしたことがすべてパーになっちまったんだよ！","ENG":"All the work we did with viral companies to taint the village’s reputation is gone now!","TWN":"我們委託霉體公司操弄輿論的計畫都毀啦！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하아, 그 촌티 나는 꼬맹이도 있네? 포기 안 한 건가?","JPN":"へー、あの田舎臭いガキもいるじゃん。まだ諦めてないんだ？","ENG":"Oh, there’s that lame kid. So they haven’t given up yet?","TWN":"哈，那個土包子小鬼也在喔？還沒放棄嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"처음부터 말도 안 되는 계획이었어. 헛소문을 흘려서 쫓아내겠다니.","JPN":"最初からでたらめな計画だったんだ。デマを流して追い出すなんて。","ENG":"It was never going to work. Spreading rumors won’t drive them away.","TWN":"這個計畫從一開始就很荒謬，怎麼可能靠著散播謠言把村民趕走！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐래. 좋다고 할 땐 언제고 이제 와서 딴소리야.","JPN":"は？　いいアイデアって言ったくせに今更？","ENG":"What? You agreed, and now you’re complaining?","TWN":"你說什麼？那時候明明你也同意的，現在才在馬後炮。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"내가 아니라 클라이언트가 문제야.","JPN":"俺じゃなくて、クライアントが問題だ。","ENG":"I’m not the problem, it’s the client.","TWN":"重點不是我，重點是客戶！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"방금 막 연락이 왔다. <color=#ffd34c>그 녀석</color>을 쓰라고 말이야.","JPN":"ちょうど今連絡が来た。<color=#ffd34c>あいつ</color>を使えと。","ENG":"They just called. They want us to use <color=#ffd34c>it</color>.","TWN":"剛剛收到消息，要出動<color=#ffd34c>那個東西</color>！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"앙? 그로니아에서 반군 놈들이 빼돌렸다던 그거 말야?","JPN":"あ？　グロニアで反乱軍の連中が引き抜いたアレか？","ENG":"Huh? The device that Gronia rebels stole?","TWN":"嗯？在格羅尼亞被叛軍偷走的那個嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그래. 기한을 넘기면 피 보는 건 우리야. 너도 그렇게 알고 있어.","JPN":"ああ。期限を過ぎるとヤバいことになるのは俺らだ。","ENG":"Yes. It’ll be on us if we don’t finish the job in time. You remember that.","TWN":"沒錯，萬一沒達成客戶的委託，到時候你跟我們都要倒大楣！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};